jQuery(document).ready(function ($) {

    // ==================== Utility Functions ====================
    const UI = {
        //showLoading: () => $('#rwwcl-spinnerModal').removeClass('rwwcl-hidden'),
        //hideLoading: () => $('#rwwcl-spinnerModal').addClass('rwwcl-hidden'),
        showToast: (message, type = 'default', duration = 2000) => {
            const toast = document.createElement('div');
            toast.className = `rwwcl-toast rwwcl-toast-${type}`;
            toast.textContent = message;
            document.body.appendChild(toast);
            setTimeout(() => {
                toast.classList.add('fade-out');
                toast.addEventListener('transitionend', () => toast.remove());
            }, duration);
        }
    };
    // ==================== Star Rating Widget ====================
    class RatingWidget {
        constructor(containerSelector) {
            this.$container = $(containerSelector);
            this.$stars = this.$container.find('.rwwcl-star');
            this.$ratingInput = $('#rwwcl-rating-value');
            this.currentRating = 0;

            if (this.$stars.length === 0) {
                console.error('No stars found! Check HTML structure');
                return;
            }

            this.init();
        }

        init() {
            this.bindEvents();
            window.rwwclRatingWidget = this;
            this.displayRating(0);
        }

        bindEvents() {
            this.$stars.on('mousemove', (e) => this.handleMouseMove(e));
            this.$stars.on('click', (e) => this.handleClick(e));
            this.$container.on('mouseleave', () => {
                this.displayRating(this.currentRating);
            });
        }

        handleMouseMove(e) {
            const $star = $(e.target);
            const isLeftHalf = e.offsetX < $star.width() / 2;

            this.$stars.removeClass('rwwcl-hover rwwcl-half');

            if (isLeftHalf) {
                $star.addClass('rwwcl-half');
                $star.nextAll('.rwwcl-star').addClass('rwwcl-hover');
            } else {
                $star.addClass('rwwcl-hover');
                $star.nextAll('.rwwcl-star').addClass('rwwcl-hover');
            }
        }

        handleClick(e) {
            const $star = $(e.target);
            const value = e.offsetX < $star.width() / 2
                ? parseFloat($star.data('value')) - 0.5
                : parseFloat($star.data('value'));

            this.setRating(value);
        }

        setRating(value) {
            this.currentRating = value;
            this.$ratingInput.val(value).trigger('change');
            this.displayRating(value);
        }

        displayRating(value) {
            // 先移除所有状态类
            this.$stars.removeClass('rwwcl-selected rwwcl-half-selected rwwcl-hover rwwcl-half');

            if (value === 0) return;

            this.$stars.each((_, star) => {
                const $star = $(star);
                const starValue = parseFloat($star.data('value'));

                if (value >= starValue) {
                    $star.addClass('rwwcl-selected');
                } else if (value >= starValue - 0.5 && value < starValue) {
                    $star.addClass('rwwcl-half-selected');
                }
            });
        }

        getRating() {
            return this.currentRating;
        }

        reset() {
            this.setRating(0);
        }
    }

    // ==================== Feedback Form Functionality ====================
    class FeedbackManager {
        constructor(ratingWidget) {
            this.ratingWidget = ratingWidget;
            this.$submitBtn = $('#rwwcl_send_feedback');
            this.init();
        }

        init() {
            this.$submitBtn.on('click', () => this.submit());
        }

        submit() {
            const data = {
                rating: this.ratingWidget.getRating(),
                type: $('#rwwcl_feedback_type').val(),
                message: $('#rwwcl_feedback_message').val(),
                email: $('#rwwcl_feedback_email').val()
            };

            // Validation
            if (!data.type) {
                UI.showToast('Please select feedback type', 'warning');
                return;
            }

            if (data.rating === 0 && (!data.message || data.message.trim() === '')) {
                UI.showToast('Please either rate or write something', 'warning');
                return;
            }

            // 保存原始文本并设置加载状态
            this.setLoading(true);

            const finalMessage = data.message && data.message.trim() !== ''
                ? data.message.trim()
                : '[No message provided]';

            $.ajax({
                url: ajaxurl,
                type: 'POST',
                data: {
                    action: 'rwwcl_send_feedback',
                    rating: data.rating,
                    feedback_type: data.type,
                    message: finalMessage,
                    user_email: data.email,
                    nonce: typeof rwwclFeedbackObject !== 'undefined' ? rwwclFeedbackObject.nonce : ''
                },
                success: (response) => this.handleSuccess(response),
                error: () => this.handleError(),
                complete: () => {
                    // 恢复按钮状态
                    this.setLoading(false);
                }
            });
        }

        setLoading(isLoading) {
            if (isLoading) {
                this.$submitBtn.data('original-text', this.$submitBtn.text());
                this.$submitBtn
                    .prop('disabled', true)
                    .addClass('rwwcl-btn-loading')
                    .html('<span class="dashicons dashicons-update"></span> Sending...');
            } else {
                this.$submitBtn
                    .prop('disabled', false)
                    .removeClass('rwwcl-btn-loading')
                    .text(this.$submitBtn.data('original-text') || 'Send Feedback');
            }
        }

        getLoadingText() {
            // 可以从本地化对象获取，或者直接返回
            return typeof rwwclFeedbackObject !== 'undefined'
                ? (rwwclFeedbackObject.strings?.submitting || 'Sending...')
                : 'Sending...';
        }

        handleSuccess(response) {
            if (response.success) {
                UI.showToast('Thank you for your feedback!', 'success');
                this.resetForm();
            } else {
                UI.showToast('Error: ' + response.data, 'error');
            }
        }

        handleError() {
            UI.showToast('An error occurred. Please try again.', 'error');
        }

        resetForm() {
            $('#rwwcl_feedback_type').val('general');
            $('#rwwcl_feedback_message').val('');
            $('#rwwcl_feedback_email').val('');
            this.ratingWidget.reset();
        }
    }

    // ==================== Initialize All Features ====================
    setTimeout(function() {
        // 检查是否存在 RW WebP 特有的 AJAX 对象
        if (typeof rwwclFeedbackObject !== 'undefined') {
            // 如果有设置页面，取消注释
            // new SettingsManager();

            // 检查星星容器是否存在
            if ($('#rwwcl-rating-container').length) { // 修改容器 ID
                const ratingWidget = new RatingWidget('#rwwcl-rating-container');
                new FeedbackManager(ratingWidget);
            } else {
                console.log('Rating container not found - feedback form may not be present on this page');
            }
        } else {
            console.log('rwwclFeedbackObject not defined - feedback functionality disabled');
        }
    }, 100);
});